1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function calculateItemPremium(item: any): number {
14	  const base = BASE_PREMIUMS[item.type];
15	  let premium = base;
16	  if (item.cursed) {
17	    premium += base * 0.5;
18	  }
19	  if (item.enchantment >= 5) {
20	    premium += base * 0.3;
21	  }
22	  return premium;
23	}
24	
25	export function claimOffice(input: any): unknown {
26	  const items = input.steps[0].items;
27	  let itemsTotal = items.reduce(
28	    (sum: number, item: any) => sum + calculateItemPremium(item),
29	    0,
30	  );
31	
32	  const typeCounts: Record<string, number> = {};
33	  for (const item of items) {
34	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
35	  }
36	  for (const type in typeCounts) {
37	    if (typeCounts[type] === 3) {
38	      itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
39	    }
40	  }
41	
42	  const premium = itemsTotal + PROCESSING_FEE;
43	  return { results: [{ premium }] };
44	}
